    kpis: ["Fraudulent Claims Detected (target: 5-15% reduction)", "Identity Verification Completion Rate (target: >90%)", "Average Claim Processing Time (target: 5-10% reduction due to reduced fraud investigation)", "Customer Satisfaction Score for Claims Process (target: >85% for legitimate claims)"],
